import{_ as a,o as l,c as o,ag as s}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"Yumina 创作者文档 实施计划","description":"","frontmatter":{},"headers":[],"relativePath":"plans/2026-03-23-creator-docs-plan.md","filePath":"plans/2026-03-23-creator-docs-plan.md","lastUpdated":null}'),r={name:"plans/2026-03-23-creator-docs-plan.md"};function i(t,e,n,c,d,u){return l(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="yumina-创作者文档-实施计划" tabindex="-1">Yumina 创作者文档 实施计划 <a class="header-anchor" href="#yumina-创作者文档-实施计划" aria-label="Permalink to &quot;Yumina 创作者文档 实施计划&quot;">​</a></h1><blockquote><p><strong>For Claude:</strong> REQUIRED SUB-SKILL: Use superpowers:executing-plans to implement this plan task-by-task.</p></blockquote><p><strong>Goal:</strong> 编写完整的 Yumina 中文创作者文档（双轨制：教程 + 参考手册）</p><p><strong>Architecture:</strong> Markdown 文件放在 <code>docs/creator-guide/</code>，每章独立文件，README 作为导航。每个复杂功能章节包含 🟢简单版 和 🔵详细版 两层。</p><p><strong>Tech Stack:</strong> Markdown, 参考 Yumina engine/shared/app 源码</p><p><strong>注意:</strong> <code>02-tutorial-advanced.md</code>（壺中の毒高级教程）暂不编写，留待后续。</p><hr><h3 id="task-1-readme-导航页" tabindex="-1">Task 1: README 导航页 <a class="header-anchor" href="#task-1-readme-导航页" aria-label="Permalink to &quot;Task 1: README 导航页&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/README.md</code></li></ul><p><strong>内容:</strong></p><ul><li>文档标题和一句话介绍</li><li>完整目录，分三部分（创作之旅 / 功能参考 / 附录）</li><li>每章一行链接 + 一句话描述</li><li>&quot;怎么用这份文档&quot;的简短说明</li></ul><hr><h3 id="task-2-欢迎页" tabindex="-1">Task 2: 欢迎页 <a class="header-anchor" href="#task-2-欢迎页" aria-label="Permalink to &quot;Task 2: 欢迎页&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/00-welcome.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/app/src/features/hub/featured-section.tsx</code>（精选世界列表）</li></ul><p><strong>内容:</strong></p><ul><li>Yumina 是什么（一句话定义 + 展开）</li><li>创作者能做什么（能力概览列表）</li><li>文档使用指南（教程路径 vs 参考手册）</li><li>&quot;5分钟感受&quot;（引导去体验精选世界）</li></ul><hr><h3 id="task-3-核心概念速览" tabindex="-1">Task 3: 核心概念速览 <a class="header-anchor" href="#task-3-核心概念速览" aria-label="Permalink to &quot;Task 3: 核心概念速览&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/01-core-concepts.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/engine/src/types/index.ts</code>（核心类型定义）</li><li><code>packages/engine/src/world/schema.ts</code>（WorldDefinition）</li></ul><p><strong>内容:</strong></p><ul><li>7个核心概念各用一段大白话解释：世界、词条、变量、指令、规则、组件、渲染器</li><li>ASCII/文字流程图：词条→提示词→AI→指令→变量→规则→渲染</li><li>概念之间的关系说明</li></ul><hr><h3 id="task-4-普通版教程-no-i-am-not-human" tabindex="-1">Task 4: 普通版教程（No, I am not human） <a class="header-anchor" href="#task-4-普通版教程-no-i-am-not-human" aria-label="Permalink to &quot;Task 4: 普通版教程（No, I am not human）&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/02-tutorial-basic.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>sample card/No__I_m_not_a_Human.json</code>（世界定义）</li></ul><p><strong>内容:</strong></p><ul><li>以 &quot;No, I am not human&quot; 为蓝本，手把手教创建类似世界</li><li>步骤：创建世界 → 写角色词条 → 写开场白 → 创建变量 → 教AI用指令 → 加HUD组件 → 加世界书词条 → 测试发布</li><li>每步配截图位置标记（<code>[截图：xxx]</code>占位）</li><li>口语化风格，像朋友在旁边教</li></ul><hr><h3 id="task-5-词条与世界书" tabindex="-1">Task 5: 词条与世界书 <a class="header-anchor" href="#task-5-词条与世界书" aria-label="Permalink to &quot;Task 5: 词条与世界书&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/03-entries-and-lorebook.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/engine/src/world/schema.ts</code>（WorldEntry 定义）</li><li><code>packages/engine/src/prompts/prompt-builder.ts</code>（词条如何组装进提示词）</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：词条是什么、角色类型、关键词触发</li><li>🔵 详细版：全字段、四大区域、深度、模糊匹配、二级关键词、递归、文件夹</li><li>💡 例子：角色词条、场景词条、条件触发词条</li></ul><hr><h3 id="task-6-变量系统" tabindex="-1">Task 6: 变量系统 <a class="header-anchor" href="#task-6-变量系统" aria-label="Permalink to &quot;Task 6: 变量系统&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/04-variables.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/engine/src/world/schema.ts</code>（Variable 定义）</li><li><code>packages/engine/src/state/game-state-manager.ts</code>（状态管理）</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：四种类型、怎么创建、默认值</li><li>🔵 详细版：9种操作、min/max、分类、嵌套路径、behaviorRules</li><li>💡 例子：HP变量、背包数组、角色关系JSON</li></ul><hr><h3 id="task-7-ai指令与宏" tabindex="-1">Task 7: AI指令与宏 <a class="header-anchor" href="#task-7-ai指令与宏" aria-label="Permalink to &quot;Task 7: AI指令与宏&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/05-directives-and-macros.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/engine/src/parser/response-parser.ts</code>（指令解析）</li><li><code>packages/engine/src/prompts/prompt-builder.ts</code>（宏展开）</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：基本语法、3个常用宏</li><li>🔵 详细版：所有语法变体、完整宏表、JSON Patch、音频指令、解析流程</li><li>💡 例子：战斗扣血、获得物品、切换场景</li></ul><hr><h3 id="task-8-行为规则引擎" tabindex="-1">Task 8: 行为规则引擎 <a class="header-anchor" href="#task-8-行为规则引擎" aria-label="Permalink to &quot;Task 8: 行为规则引擎&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/06-rules-engine.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/engine/src/rules/rules-engine.ts</code></li><li><code>packages/engine/src/reactions/reaction-evaluator.ts</code></li><li><code>packages/engine/src/world/schema.ts</code>（Rule 定义）</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：WHEN/IF/THEN、最简例子</li><li>🔵 详细版：9种触发器、7种运算符、8种动作、注入位置、优先级/冷却/次数</li><li>💡 例子：HP归零游戏结束、进入区域触发描述、回合计时器</li></ul><hr><h3 id="task-9-组件系统" tabindex="-1">Task 9: 组件系统 <a class="header-anchor" href="#task-9-组件系统" aria-label="Permalink to &quot;Task 9: 组件系统&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/07-components.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/engine/src/types/components.ts</code></li><li><code>packages/app/src/features/session/game-panel/</code>（组件渲染）</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：5种组件介绍、最简配置</li><li>🔵 详细版：每种组件全部字段、变量绑定、Web Panel</li><li>💡 例子：HP血条、背包格子、场景图片</li></ul><hr><h3 id="task-10-自定义消息渲染器" tabindex="-1">Task 10: 自定义消息渲染器 <a class="header-anchor" href="#task-10-自定义消息渲染器" aria-label="Permalink to &quot;Task 10: 自定义消息渲染器&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/08-message-renderer.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/app/src/features/session/message-list/</code>（渲染逻辑）</li><li><code>sample card/</code> 中的渲染器代码</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：渲染器是什么、效果对比</li><li>🔵 详细版：TSX入门、Props接口、模板、三种渲染方式区别</li><li>💡 例子：简单气泡渲染器、带角色头像的渲染器</li></ul><hr><h3 id="task-11-音频系统" tabindex="-1">Task 11: 音频系统 <a class="header-anchor" href="#task-11-音频系统" aria-label="Permalink to &quot;Task 11: 音频系统&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/09-audio.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/engine/src/world/schema.ts</code>（AudioTrack, BGMPlaylist, ConditionalBGM）</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：加BGM、三种类型</li><li>🔵 详细版：播放列表、条件触发、AI指令、淡入淡出、链式播放</li><li>💡 例子：循环BGM、战斗切歌、环境音</li></ul><hr><h3 id="task-12-ai模型与设置" tabindex="-1">Task 12: AI模型与设置 <a class="header-anchor" href="#task-12-ai模型与设置" aria-label="Permalink to &quot;Task 12: AI模型与设置&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/10-ai-settings.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/engine/src/world/schema.ts</code>（WorldSettings）</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：temperature/max_tokens概念、推荐值</li><li>🔵 详细版：全参数、扫描深度、递归深度、structuredOutput</li><li>💡 例子：不同风格的推荐设置</li></ul><hr><h3 id="task-13-发布、导出与bundle" tabindex="-1">Task 13: 发布、导出与Bundle <a class="header-anchor" href="#task-13-发布、导出与bundle" aria-label="Permalink to &quot;Task 13: 发布、导出与Bundle&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/11-publish-and-share.md</code></li></ul><p><strong>源码参考:</strong></p><ul><li><code>packages/server/src/routes/worlds.ts</code></li><li><code>packages/engine/src/world/schema.ts</code>（YuminaBundle）</li></ul><p><strong>内容:</strong></p><ul><li>🟢 简单版：发布流程、可见性</li><li>🔵 详细版：Bundle系统、JSON导出、标签分级、多人模式</li><li>💡 例子：发布检查清单</li></ul><hr><h3 id="task-14-术语表" tabindex="-1">Task 14: 术语表 <a class="header-anchor" href="#task-14-术语表" aria-label="Permalink to &quot;Task 14: 术语表&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/12-glossary.md</code></li></ul><p><strong>内容:</strong></p><ul><li>所有术语按拼音/字母排序</li><li>每个术语一句话解释 + 对应英文</li><li>涵盖：世界、词条、变量、指令、规则、组件、渲染器、Bundle、宏、触发器等</li></ul><hr><h3 id="task-15-常见问题" tabindex="-1">Task 15: 常见问题 <a class="header-anchor" href="#task-15-常见问题" aria-label="Permalink to &quot;Task 15: 常见问题&quot;">​</a></h3><p><strong>Files:</strong></p><ul><li>Create: <code>docs/creator-guide/13-faq.md</code></li></ul><p><strong>内容:</strong></p><ul><li>分类整理：创作基础、变量与指令、规则、组件、发布</li><li>每个问题简短回答 + 指向相关章节的链接</li></ul>',120)])])}const h=a(r,[["render",i]]);export{g as __pageData,h as default};
